package courses

import (
	"context"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

const PAGE_SIZE = 200;

type CoursesService struct {
	queries * db.Queries;
}

type CoursesItem struct {
	courseId string;
	title string;
}

func NewCoursesService(queries *db.Queries) *CoursesService{
	return &CoursesService{queries:queries}
}

func (courses *CoursesService)List(ctx context.Context, nextCursor string){
	var cursor pgtype.UUID

	if (nextCursor != ""){
		cursor.Scan(nextCursor);
	}

	courses.queries.GetCourses(ctx, db.GetCoursesParams{ Cursor: cursor, Size: PAGE_SIZE})

}

package courses

import (
	"net/http"
)

type CoursesHandlers struct {
	courses *CoursesService
}



func NewCoursesHandlers(service *CoursesService) *CoursesHandlers {
	return &CoursesHandlers{ courses:service }

}

func (handler *CoursesHandlers)GetCoursesHandler(w http.ResponseWriter, r * http.Request){
    nextCursor := r.URL.Query().Get("nextCursor")

	handler.courses.GetCourses(nextCursor)
}

